} from "../extensions/LSP8NonTransferable/LSP8NonTransferableInitAbstract.sol";
import {
    LSP8RevokableInitAbstract
} from "../extensions/LSP8Revokable/LSP8RevokableInitAbstract.sol";

// constants
import {
